/* Firmware OTA update manager */
#ifndef OTA_MGR_H
#define OTA_MGR_H

#include <stdint.h>

#define OTA_MAX_VERSION_LEN  16

typedef struct {
    uint8_t  major;
    uint8_t  minor;
    uint8_t  patch;
    char     build_tag[OTA_MAX_VERSION_LEN];
} ota_version_t;

/* Begin an OTA session; returns session token or negative error */
int32_t ota_begin(const ota_version_t *new_version);

/* Write a chunk of firmware data */
int ota_write_chunk(int32_t token, const uint8_t *data, uint32_t len);

/* Finalize and verify; returns 0 if image is valid */
int ota_commit(int32_t token);

/* Abort an in-progress OTA session */
void ota_abort(int32_t token);

#endif

