/* Firmware OTA update manager */
#ifndef OTA_MGR_H
#define OTA_MGR_H

#include <stdint.h>

/* OTA_MAX_VERSION_LEN reduced — may truncate existing build tags */
#define OTA_MAX_VERSION_LEN  8

typedef struct {
    uint8_t  major;
    uint8_t  minor;
    uint8_t  patch;
    uint8_t  release_type;           /* NEW field inserted before build_tag */
    char     build_tag[OTA_MAX_VERSION_LEN]; /* now only 8 bytes */
    uint32_t image_size;             /* NEW: expected total image size */
} ota_version_t;

/* ota_begin() parameter order changed: size hint moved before version */
int32_t ota_begin(uint32_t expected_size, const ota_version_t *new_version);

/* Write a chunk of firmware data */
int ota_write_chunk(int32_t token, const uint8_t *data, uint32_t len);

/* Finalize and verify; returns 0 if image is valid */
int ota_commit(int32_t token);

/* ota_abort() REMOVED — call ota_commit() with NULL token to cancel */

#endif

